const d = $input.first().json.body;

// ── Helpers ────────────────────────────────────────────────────────────────
const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const br = (v) => esc(v).replace(/\n/g, '<br/>');
const euro = (v) => new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(v);
const dateFmt = (d) => new Intl.DateTimeFormat('nl-NL', { dateStyle: 'long' }).format(d);

// ── Gegevens ───────────────────────────────────────────────────────────────
const vandaag = new Date();
const geldigTot = new Date(vandaag); geldigTot.setDate(geldigTot.getDate() + 30);

const fromName = esc(d.from?.companyName ?? '');
const fromEmail = esc(d.from?.email ?? '');
const fromWebsite = esc(d.from?.websiteUrl ?? '');
const fromAddress = br(d.from?.address ?? '');
const fromVat = esc(d.from?.vatNumber ?? '');
const fromKvk = esc(d.from?.kvkNumber ?? '');
const offerteNr = 'WVW-' + vandaag.getFullYear() + '-' + String(d.proposalId ?? '').slice(-6).toUpperCase();
const exclBtw = d.amount != null ? Number(d.amount) : null;
const btwBedrag = exclBtw != null ? exclBtw * 0.21 : null;
const inclBtw = exclBtw != null ? exclBtw + btwBedrag : null;

const scopeItems = d.scope
  ? String(d.scope).split('\n').map(l => l.trim()).filter(Boolean).map(l => `<li>${esc(l)}</li>`).join('')
  : '';

// ── HTML ───────────────────────────────────────────────────────────────────
const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Helvetica Neue', Arial, sans-serif; font-size: 13px; line-height: 1.6; color: #1a1a1a; background: #fff; padding: 52px 56px; }

  /* ── Header ── */
  .page-header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 28px; border-bottom: 3px solid #111; margin-bottom: 36px; }
  .company-name { font-size: 24px; font-weight: 800; color: #111; letter-spacing: -.5px; }
  .company-sub { font-size: 11px; color: #666; margin-top: 3px; }
  .doc-title { text-align: right; }
  .doc-title h1 { font-size: 28px; font-weight: 800; color: #111; letter-spacing: -1px; }
  .doc-title .meta { font-size: 11px; color: #555; line-height: 1.9; margin-top: 4px; }
  .doc-title .meta strong { color: #111; }

  /* ── Partijen ── */
  .parties { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-bottom: 36px; }
  .party { background: #f8f9fa; border-radius: 8px; padding: 18px 20px; }
  .party-label { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .1em; color: #999; margin-bottom: 8px; }
  .party-name { font-size: 14px; font-weight: 700; color: #111; margin-bottom: 2px; }
  .party-detail { font-size: 12px; color: #444; line-height: 1.7; }

  /* ── Secties ── */
  .section { margin-bottom: 28px; }
  .section-title { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #666; border-bottom: 1px solid #e5e7eb; padding-bottom: 6px; margin-bottom: 12px; }
  .section p { font-size: 13px; color: #333; line-height: 1.75; }
  .section ul { padding-left: 20px; }
  .section ul li { font-size: 13px; color: #333; line-height: 1.8; }

  /* ── Prijstabel ── */
  .price-table { width: 100%; border-collapse: collapse; margin-bottom: 28px; }
  .price-table td { padding: 9px 12px; font-size: 13px; border-bottom: 1px solid #f0f0f0; }
  .price-table td:last-child { text-align: right; font-variant-numeric: tabular-nums; }
  .price-table .total-row td { font-size: 16px; font-weight: 700; color: #111; border-top: 2px solid #111; border-bottom: none; padding-top: 12px; }
  .price-table .muted { color: #888; font-size: 12px; }

  /* ── Betaling ── */
  .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 28px; }
  .info-card { border: 1px solid #e5e7eb; border-radius: 8px; padding: 14px 16px; }
  .info-card .label { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #999; margin-bottom: 4px; }
  .info-card .value { font-size: 13px; color: #111; font-weight: 600; }
  .info-card .sub { font-size: 11px; color: #666; margin-top: 2px; }

  /* ── Akkoord ── */
  .akkoord { margin-top: 40px; border: 1px solid #e5e7eb; border-radius: 8px; padding: 24px; }
  .akkoord-title { font-size: 13px; font-weight: 700; color: #111; margin-bottom: 8px; }
  .akkoord-text { font-size: 12px; color: #555; line-height: 1.7; margin-bottom: 28px; }
  .sig-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; }
  .sig-box .sig-label { font-size: 11px; color: #888; margin-bottom: 4px; }
  .sig-box .sig-line { border-bottom: 1px solid #aaa; height: 40px; margin-bottom: 6px; }
  .sig-box .sig-name { font-size: 12px; color: #444; }

  /* ── Footer ── */
  .page-footer { margin-top: 40px; padding-top: 14px; border-top: 1px solid #e5e7eb; font-size: 10px; color: #aaa; line-height: 1.8; text-align: center; }
</style>
</head>
<body>

<!-- ── HEADER ── -->
<div class="page-header">
  <div>
    <div class="company-name">${fromName}</div>
    <div class="company-sub">${fromWebsite}${fromWebsite && fromEmail ? ' &nbsp;·&nbsp; ' : ''}${fromEmail}</div>
  </div>
  <div class="doc-title">
    <h1>OFFERTE</h1>
    <div class="meta">
      <strong>Offertenummer:</strong> ${offerteNr}<br/>
      <strong>Datum:</strong> ${dateFmt(vandaag)}<br/>
      <strong>Geldig tot:</strong> ${dateFmt(geldigTot)}
    </div>
  </div>
</div>

<!-- ── PARTIJEN ── -->
<div class="parties">
  <div class="party">
    <div class="party-label">Aanbieder</div>
    <div class="party-name">${fromName}</div>
    <div class="party-detail">
      ${fromAddress ? fromAddress + '<br/>' : ''}
      ${fromEmail}<br/>
      ${fromWebsite ? fromWebsite + '<br/>' : ''}
      ${fromVat ? 'BTW: ' + fromVat + '<br/>' : ''}
      ${fromKvk ? 'KvK: ' + fromKvk : ''}
    </div>
  </div>
  <div class="party">
    <div class="party-label">Opdrachtgever</div>
    <div class="party-name">${esc(d.recipientCompany ?? d.recipientName ?? '')}</div>
    <div class="party-detail">
      ${d.recipientCompany && d.recipientName ? esc(d.recipientName) + '<br/>' : ''}
      ${d.recipientAddress ? br(d.recipientAddress) + '<br/>' : ''}
      ${esc(d.recipientEmail ?? '')}
    </div>
  </div>
</div>

<!-- ── ONDERWERP ── -->
<div class="section">
  <div class="section-title">Onderwerp</div>
  <p><strong>${esc(d.title ?? '')}</strong></p>
</div>

<!-- ── OMSCHRIJVING ── -->
<div class="section">
  <div class="section-title">Omschrijving werkzaamheden</div>
  <p>${br(d.summary ?? '')}</p>
</div>

${scopeItems ? `
<!-- ── SCOPE ── -->
<div class="section">
  <div class="section-title">Scope</div>
  <ul>${scopeItems}</ul>
</div>` : ''}

${d.deliveryTime ? `
<!-- ── PLANNING ── -->
<div class="section">
  <div class="section-title">Planning &amp; doorlooptijd</div>
  <p>${esc(d.deliveryTime)}</p>
</div>` : ''}

${d.notes ? `
<!-- ── OPMERKINGEN ── -->
<div class="section">
  <div class="section-title">Opmerkingen</div>
  <p>${br(d.notes)}</p>
</div>` : ''}

${exclBtw != null ? `
<!-- ── PRIJS ── -->
<div class="section">
  <div class="section-title">Prijsopgave</div>
  <table class="price-table">
    <tr>
      <td>${esc(d.priceLabel ?? 'Projectprijs')}</td>
      <td>${euro(exclBtw)}</td>
    </tr>
    <tr>
      <td class="muted">BTW 21%</td>
      <td class="muted">${euro(btwBedrag)}</td>
    </tr>
    <tr class="total-row">
      <td>Totaal incl. BTW</td>
      <td>${euro(inclBtw)}</td>
    </tr>
  </table>
</div>

<!-- ── BETAALINFO ── -->
<div class="info-grid">
  <div class="info-card">
    <div class="label">Aanbetaling</div>
    <div class="value">${euro(inclBtw * 0.5)} (50%)</div>
    <div class="sub">Te voldoen bij akkoord</div>
  </div>
  <div class="info-card">
    <div class="label">Restbetaling</div>
    <div class="value">${euro(inclBtw * 0.5)} (50%)</div>
    <div class="sub">Te voldoen bij oplevering</div>
  </div>
</div>` : ''}

<!-- ── AKKOORD ── -->
<div class="akkoord">
  <div class="akkoord-title">Akkoordverklaring</div>
  <div class="akkoord-text">
    Door ondertekening verklaart de opdrachtgever akkoord te gaan met de inhoud van deze offerte en de algemene voorwaarden van ${fromName}.
    Na ondertekening is deze offerte juridisch bindend. De algemene voorwaarden zijn op te vragen via <strong>${fromWebsite || fromEmail}</strong>
    of worden op verzoek toegestuurd.
  </div>
  <div class="sig-grid">
    <div class="sig-box">
      <div class="sig-label">Handtekening opdrachtgever</div>
      <div class="sig-line"></div>
      <div class="sig-name">${esc(d.recipientName ?? '')} &nbsp;·&nbsp; ${dateFmt(vandaag)}</div>
    </div>
    <div class="sig-box">
      <div class="sig-label">Handtekening ${fromName}</div>
      <div class="sig-line"></div>
      <div class="sig-name">${fromName} &nbsp;·&nbsp; ${dateFmt(vandaag)}</div>
    </div>
  </div>
</div>

<!-- ── FOOTER ── -->
<div class="page-footer">
  ${fromName}${fromEmail ? ' &nbsp;·&nbsp; ' + fromEmail : ''}${fromWebsite ? ' &nbsp;·&nbsp; ' + fromWebsite : ''}<br/>
  ${fromVat ? 'BTW: ' + fromVat + ' &nbsp;·&nbsp; ' : ''}${fromKvk ? 'KvK: ' + fromKvk + ' &nbsp;·&nbsp; ' : ''}Offertenummer ${offerteNr} &nbsp;·&nbsp; Geldig tot ${dateFmt(geldigTot)}
</div>

</body>
</html>`;

return [{ json: { ...d, html } }];
